    document.getElementById('nt-reg-url').value = '';
    document.getElementById('nt-reg-class').value = '';
    document.getElementById('nt-reg-target').value = '';
}

function closeNativeTrapEditor() {
    document.getElementById('native-trap-list-view').style.display = 'block';
    document.getElementById('native-trap-editor-view').style.display = 'none';
}

function saveNativeTrapToRegistry() {
    const id = document.getElementById('edit-native-trap-id').value || 'ntrap_' + Date.now();
    const newTrap = {
        id: id,
        label: document.getElementById('nt-reg-label').value.trim() || 'Unnamed Native',
        url: document.getElementById('nt-reg-url').value.trim(),
        class_name: document.getElementById('nt-reg-class').value.trim(),
        target: document.getElementById('nt-reg-target').value.trim(),
        strict: document.getElementById('nt-reg-strict').value,
        timeout: document.getElementById('nt-reg-timeout').value,
        dim: document.getElementById('nt-reg-dim').value
    };
    if (!newTrap.url || !newTrap.class_name || !newTrap.target) return toast("REQUIRED FIELDS MISSING", "danger");
    const registry = JSON.parse(localStorage.getItem('cortex_native_registry') || '[]');
    const idx = registry.findIndex(t => t.id === id);
    if (idx > -1) registry[idx] = newTrap;
    else registry.push(newTrap);
    localStorage.setItem('cortex_native_registry', JSON.stringify(registry));
    selectedNativeTrapId = id;
    closeNativeTrapEditor();
    renderNativeTrapList();
    toast("NATIVE_VAULT_UPDATED", "success");
}

function editNativeTrap(id) {
    const registry = JSON.parse(localStorage.getItem('cortex_native_registry') || '[]');
    const trap = registry.find(t => t.id === id);
    if (!trap) return;
    openNativeTrapEditor();
    document.getElementById('edit-native-trap-id').value = trap.id;
    document.getElementById('nt-reg-label').value = trap.label;
    document.getElementById('nt-reg-url').value = trap.url;
    document.getElementById('nt-reg-class').value = trap.class_name;
    document.getElementById('nt-reg-target').value = trap.target;
    document.getElementById('nt-reg-strict').value = trap.strict;
    document.getElementById('nt-reg-timeout').value = trap.timeout;
    document.getElementById('nt-reg-dim').value = trap.dim;
}

function deleteNativeTrap(id) {
    if (!confirm("PURGE THIS NATIVE CONFIG?")) return;
    let registry = JSON.parse(localStorage.getItem('cortex_native_registry') || '[]');
    registry = registry.filter(t => t.id !== id);
    localStorage.setItem('cortex_native_registry', JSON.stringify(registry));
    if (selectedNativeTrapId === id) selectedNativeTrapId = null;
    renderNativeTrapList();
    toast("NATIVE_CONFIG_PURGED", "success");
}

function selectNativeTrap(id) {
    selectedNativeTrapId = id;
    renderNativeTrapList();
    toast("NATIVE_TRAP_ARMED", "success");
}

