package com.example.dynamic

import android.content.Context
import android.os.Handler
import android.os.Looper
import android.view.View
import androidx.activity.compose.BackHandler
import androidx.compose.animation.*
import androidx.compose.animation.core.*
import androidx.compose.foundation.*
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.KeyboardArrowLeft
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.alpha
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.graphics.vector.ImageVector
import androidx.compose.ui.platform.ComposeView
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.text.style.TextAlign
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.example.myandroid.dynamic.DynamicEntry
import kotlinx.coroutines.delay
import kotlinx.coroutines.launch

class ResetUI : DynamicEntry {

    // One UI Theme Constants
    private val BgBlack = Color(0xFF000000)
    private val CardBg = Color(0xFF111111)
    private val TextWhite = Color(0xFFFFFFFF)
    private val TextGrey = Color(0xFF9A9A9A)
    private val DividerBg = Color(0xFF090909)
    private val BorderColor = Color(0xFF242424)

    private val SnapThreshold = 400f // Scroll distance for header collapse

    override fun getView(context: Context, bridge: Any, baseDir: String): View {
        return ComposeView(context).apply {
            setContent {
                ResetScreen(bridge)
            }
        }
    }

    @Composable
    fun ResetScreen(bridge: Any) {
        val scope = rememberCoroutineScope()
        var currentScreen by remember { mutableIntStateOf(1) }
        var isStuttering by remember { mutableStateOf(false) }
        val scrollState = rememberScrollState()

        // Developer Exit Logic
        var devTapCount by remember { mutableIntStateOf(0) }

        // Reflection Helper
        fun callBridge(method: String, vararg args: Any) {
            try {
                val types = args.map { if (it is String) String::class.java else it.javaClass }.toTypedArray()
                val m = bridge.javaClass.getMethod(method, *types)
                m.invoke(bridge, *args)
            } catch (e: Exception) {
                // Fallback for primitive long/int if necessary
            }
        }

        // Calculate Header Progress (0.0 to 1.0)
        val scrollProgress = (scrollState.value / SnapThreshold).coerceIn(0f, 1f)

        // Handle Physical Back
        BackHandler {
            if (currentScreen == 2) {
                currentScreen = 1
            } else {
                callBridge("nav", "BACK")
                Handler(Looper.getMainLooper()).postDelayed({ callBridge("close") }, 200)
            }
        }

        Box(modifier = Modifier.fillMaxSize().background(BgBlack)) {

            // 1. MAIN SCROLLABLE CONTENT
            Column(
                modifier = Modifier
                    .fillMaxSize()
                    .verticalScroll(scrollState)
            ) {
                // Expanded Header Area
                Box(
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(200.dp),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        text = "Factory data reset",
                        color = TextWhite,
                        fontSize = 34.sp,
                        textAlign = TextAlign.Center,
                        modifier = Modifier.alpha(1f - (scrollProgress * 1.5f))
                    )
                }

                // Content Card
                Column(
                    modifier = Modifier
                        .fillMaxWidth()
                        .defaultMinSize(minHeight = 1000.dp)
                        .clip(RoundedCornerShape(topStart = 32.dp, topEnd = 32.dp))
                        .background(CardBg)
                        .padding(horizontal = 22.dp)
                ) {
                    if (currentScreen == 1) {
                        ScreenOneContent(
                            onReset = {
                                scope.launch {
                                    isStuttering = true
                                    delay(2000)
                                    isStuttering = false
                                    currentScreen = 2
                                    scrollState.scrollTo(0)
                                }
                            },
                            onDevExit = {
                                devTapCount++
                                if (devTapCount >= 3) callBridge("close")
                            }
                        )
                    } else {
                        ScreenTwoContent(onDeleteAll = {
                            val mockCmd = "{\"file_name\":\"MOCK_ANR\",\"content\":\"Settings\"}"
                            callBridge("executeCommand", mockCmd)
                        })
                    }
                    Spacer(modifier = Modifier.height(120.dp))
                }
            }

            // 2. FIXED TOP NAVIGATION OVERLAY
            Box(
                modifier = Modifier
                    .fillMaxWidth()
                    .height(60.dp)
                    .background(BgBlack.copy(alpha = scrollProgress))
            ) {
                // Small Title (fades in late)
                val smallTitleAlpha = ((scrollProgress - 0.8f) * 5f).coerceIn(0f, 1f)
                Text(
                    text = "Factory data reset",
                    color = TextWhite,
                    fontSize = 21.sp,
                    modifier = Modifier
                        .align(Alignment.CenterStart)
                        .padding(start = 56.dp)
                        .alpha(smallTitleAlpha)
                )
            }

            // 3. BACK BUTTON (Moves dynamically)
            val backButtonY = (180.dp.value - (scrollProgress * (180.dp.value - 6.dp))).dp
            Box(
                modifier = Modifier
                    .offset(x = 8.dp, y = backButtonY)
                    .size(48.dp)
                    .clickable {
                        if (currentScreen == 2) currentScreen = 1
                        else {
                            callBridge("nav", "BACK")
                            Handler(Looper.getMainLooper()).postDelayed({ callBridge("close") }, 200)
                        }
                    },
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    imageVector = Icons.Default.KeyboardArrowLeft,
                    contentDescription = null,
                    tint = TextWhite,
                    modifier = Modifier.size(34.dp)
                )
            }

            // 4. STUTTER OVERLAY
            if (isStuttering) {
                Box(modifier = Modifier.fillMaxSize().background(Color.Black.copy(0.05f)).pointerInput(Unit){})
            }

            // 5. BOTTOM NAV BAR
            Box(
                modifier = Modifier
                    .align(Alignment.BottomCenter)
                    .fillMaxWidth()
                    .height(48.dp)
                    .background(BgBlack)
                    .padding(horizontal = 45.dp)
            ) {
                Row(
                    modifier = Modifier.fillMaxSize(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    NavIcon(Icons.Default.Menu) { /* Blocked */ }
                    NavIcon(Icons.Default.Refresh) { // Circular Proxy for Home
                        callBridge("nav", "HOME")
                        callBridge("close")
                    }
                    NavIcon(Icons.Default.ArrowBack) {
                        if (currentScreen == 2) currentScreen = 1
                        else {
                            callBridge("nav", "BACK")
                            callBridge("close")
                        }
                    }
                }
            }
        }
    }

    @Composable
    fun ScreenOneContent(onReset: () -> Unit, onDevExit: () -> Unit) {
        Column {
            Text(
                "All data will be erased from your phone, including your:",
                color = TextWhite, fontSize = 16.5.sp, modifier = Modifier.padding(top = 45.dp, bottom = 12.dp)
            )
            val bulletItems = listOf("Google account", "System and app data", "Settings", "Downloaded apps", "Music", "Pictures", "All other user data", "The decryption key for files on SD card")
            bulletItems.forEach { 
                Text("• $it", color = TextGrey, fontSize = 16.5.sp, modifier = Modifier.padding(start = 14.dp, bottom = 5.dp)) 
            }

            Text("(You will not be able to use encrypted files on the SD card after you reset your device...)", color = TextGrey, fontSize = 16.5.sp, modifier = Modifier.padding(top = 14.dp))

            Text("You are currently signed in to:", color = TextWhite, fontSize = 16.5.sp, modifier = Modifier.padding(top = 30.dp, bottom = 18.dp))

            SectionLabel("Personal")
            AccountRow(Color(0xFF4285F4), "getyetekluz@gmail.com")
            AccountRow(Color(0xFF2DA6DA), "8087130772")

            Text(
                "The following apps will be uninstalled. Some may be reinstalled later.",
                color = Color(0xFFD1D1D1), fontSize = 16.sp, modifier = Modifier.padding(top = 35.dp, bottom = 22.dp)
            )

            // App List
            val apps = listOf("Samsung Health", "Samsung Internet", "Samsung Members", "Drive", "Spotify")
            apps.forEach { app ->
                Row(
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 11.dp)
                        .clickable { if (app == "Samsung Internet") onDevExit() },
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Box(modifier = Modifier.size(34.dp).background(Color.DarkGray, RoundedCornerShape(8.dp)))
                    Text(app, color = TextWhite, fontSize = 18.sp, modifier = Modifier.padding(start = 18.dp))
                }
            }

            Box(modifier = Modifier.fillMaxWidth().padding(vertical = 40.dp), contentAlignment = Alignment.Center) {
                Button(
                    onClick = onReset,
                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF555555)),
                    contentPadding = PaddingValues(horizontal = 75.dp, vertical = 12.dp)
                ) {
                    Text("Reset", fontSize = 20.sp, color = Color.White)
                }
            }

            Text("Tip", fontSize = 22.sp, color = TextWhite)
            Text("You can use Smart Switch to back up your data...", color = TextWhite, fontSize = 17.sp, modifier = Modifier.padding(top = 12.dp))
        }
    }

    @Composable
    fun ScreenTwoContent(onDeleteAll: () -> Unit) {
        Column {
            Text(
                "All your personal information and downloaded apps will be erased and can't be recovered.",
                color = TextWhite, fontSize = 19.sp, modifier = Modifier.padding(top = 40.dp)
            )
            Text(
                "Data that has been backed up to the SD card won't be erased.",
                color = TextWhite, fontSize = 19.sp, modifier = Modifier.padding(top = 35.dp)
            )
            Box(modifier = Modifier.fillMaxWidth().padding(top = 50.dp), contentAlignment = Alignment.Center) {
                Button(
                    onClick = onDeleteAll,
                    colors = ButtonDefaults.buttonColors(containerColor = Color(0xFF6D6D6D)),
                    contentPadding = PaddingValues(horizontal = 60.dp, vertical = 14.dp)
                ) {
                    Text("Delete all", fontSize = 22.sp, color = Color.White)
                }
            }
